A decorator is a function that wraps another function to extend or modify its behaviour without changing its source code.

```python
import functools

def my_decorator(func):
    @functools.wraps(func)  # preserves func's metadata
    def wrapper(*args, **kwargs):
        print('Before call')
        result = func(*args, **kwargs)
        print('After call')
        return result
    return wrapper

@my_decorator
def say_hello(name):
    print(f'Hello, {name}!')

say_hello('Alice')
# Before call
# Hello, Alice!
# After call
```

A decorator with arguments needs an extra layer:
```python
def repeat(n):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            for _ in range(n):
                func(*args, **kwargs)
        return wrapper
    return decorator

@repeat(3)
def greet():
    print('Hi!')
```
Always use `@functools.wraps` to preserve `__name__`, `__doc__`, etc.

```python
class Animal:
    def __init__(self, name: str):
        self.name = name

    def speak(self) -> str:
        raise NotImplementedError

    def __repr__(self) -> str:
        return f'{type(self).__name__}({self.name!r})'


class Dog(Animal):
    def speak(self) -> str:
        return f'{self.name} says Woof!'


class Cat(Animal):
    def speak(self) -> str:
        return f'{self.name} says Meow!'


dog = Dog('Rex')
print(dog.speak())   # Rex says Woof!
print(repr(dog))     # Dog('Rex')

print(isinstance(dog, Animal))  # True
print(issubclass(Dog, Animal))  # True
```

Use `super()` to call the parent constructor:
```python
class Puppy(Dog):
    def __init__(self, name, age):
        super().__init__(name)
        self.age = age
```

